import{_ as e,o as t,c as r,a3 as i}from"./chunks/framework.CjquFG0V.js";const d=JSON.parse('{"title":"44. Salary Packaging","description":"","frontmatter":{"title":"44. Salary Packaging","eba":"Doctors in Training 2022-2026","topics":["wages","salary-packaging","preliminary"]},"headers":[],"relativePath":"ebas/doctors-in-training/remuneration/44-salary-packaging.md","filePath":"ebas/doctors-in-training/remuneration/44-salary-packaging.md"}'),n={name:"ebas/doctors-in-training/remuneration/44-salary-packaging.md"};function o(s,a,c,g,l,p){return t(),r("div",null,[...a[0]||(a[0]=[i('<h1 id="_44-salary-packaging" tabindex="-1">44. Salary Packaging <a class="header-anchor" href="#_44-salary-packaging" aria-label="Permalink to &quot;44. Salary Packaging&quot;">​</a></h1><p><strong>44.1</strong> By agreement with the Doctor, the rate of pay specified at <a href="/eba/ebas/doctors-in-training/appendices/2-doctors-in-training-remuneration-allowances-and-deductions.html">Appendix 2</a> may be salary packaged in accordance with the Health Service’s salary packaging program.</p><p><strong>44.2</strong> As far as possible, it is the intention of the Health Service that the Health Service maintains a worthwhile salary packaging program for all Doctors. However, if legislative or other changes have the effect of increasing the cost of packaging to the Health Service, the cost must be paid by the participating Doctor or the arrangement must be ceased by the Health Service.</p><p><strong>44.3</strong> The Health Service’s salary packaging program will not restrict the Doctor’s capacity to salary package any proportion of their salary in any one month.</p><p>Plain language terms: salary sacrifice, novated lease.</p>',5)])])}const m=e(n,[["render",o]]);export{d as __pageData,m as default};
